- (void)queryVAppWithId:(NSInteger)vappId needsFlushLocalStorage:(BOOL)needsFlush next:(void (^)(WBVAppModel * _Nullable vapp, NSError * _Nullable error))nextHandler {
    WBVAppModel *localVapp = nil;
    for(WBVAppModel* vapp in self.myApps) {
        if (vapp.vid != vappId) continue;
        if (!nextHandler) return;
        if (!needsFlush) return nextHandler(vapp, nil);
        localVapp = vapp;
        break;
    }
    [[WBNetworkManager defaultManager] getDetailVappInfoWithWithVappId:vappId callback:^(WBVAppDetailHttpModel * _Nullable vappDetailHttpModel, NSError * _Nullable error) {
        WBVAppModel *resVapp = localVapp;
        if (error) return nextHandler(nil, error);
        if (!resVapp) {
            resVapp = [WBVAppModel initWithVAppDetailModel:vappDetailHttpModel];
        } else {
            [resVapp updateWithVAppDetailModel:vappDetailHttpModel];
        }
        nextHandler(resVapp, nil);
    }];
}

- (WBVAppModel *)getLocalVAppById:(NSInteger)vappId {
    for(WBVAppModel* vapp in [WBVAppManager sharedManager].myApps) {
        if (vapp.vid != vappId) continue;
        return vapp;
    }
    return nil;
}

