+- (void)togglePretenseForVapp:(WBVAppModel *)vapp
+                    presenter:(UIViewController *)presenter
+                     setSwitch:(void(^)(BOOL on, BOOL animated))setSwitch {
+    if (WBVAppManager.sharedManager.myApps.count <= 0) {
+        if (setSwitch) setSwitch(NO, YES);
+        UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"提醒" message:@"请先安装您的第一个应用后再来开启吧" preferredStyle:UIAlertControllerStyleAlert];
+        [alert addAction:[UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:nil]];
+        UIViewController *vc = presenter ?: [WBAppManager getUIApplicationRootViewController];
+        [vc presentViewController:alert animated:YES completion:nil];
+        return;
+    }
+
+    BOOL isTurningOn = !vapp.featureStatusInfo.isPretenseSwitchOn;
+    BOOL canSwitch = [self handleSwitchBenefitFunction:WBUserBenefitPretense target:isTurningOn vapp:vapp];
+    if (!canSwitch) {
+        if (setSwitch) setSwitch(NO, YES);
+        return;
+    }
+
+    if (isTurningOn) {
+        void (^successBlock)(void) = ^{
+            NSMutableArray<WBVAppModel *> *apps = WBVAppManager.sharedManager.myApps;
+            for (WBVAppModel *item in apps) {
+                item.featureStatusInfo.isOneClickSwitchOn = NO;
+                [WBVAppManager.sharedManager saveOneClickStartStatusForVApp:item];
+            }
+
+            Class clazz = [WBSubMainViewController class];
+            if (clazz) {
+                WBLoadSubMineViewController *loadingVC = [[WBLoadSubMineViewController alloc] initWithOpen:YES];
+                loadingVC.modalPresentationStyle = UIModalPresentationOverFullScreen;
+                [presenter presentViewController:loadingVC animated:NO completion:nil];
+                dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(2.0 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
+                    [loadingVC dismissViewControllerAnimated:NO completion:^{
+                        [WBAppManager.sharedManager setRootViewController:clazz];
+                        WBSettingManager.sharedManager.IsPretending = YES;
+                        [WBEventManager logAppPretense];
+                        [self consumeUsageOnceForBenefitBit:WBUserBenefitPretense];
+                        if (setSwitch) setSwitch(NO, YES);
+                    }];
+                });
+            }
+        };
+        void (^failBlock)(void) = ^{ if (setSwitch) setSwitch(NO, YES); };
+
+        void (^alertBlock)(void) = ^{
+            if (!WBSettingManager.sharedManager.NeverShowPretenseTipAlert) {
+                NSString *content = @"即将进入AI界面，在聊天框中\n输入密码 (默认为1234) \n返回微盒主界面";
+                NSMutableAttributedString *attr = [[NSMutableAttributedString alloc] initWithString:content attributes:@{NSFontAttributeName: WBPrimaryFont(14), NSForegroundColorAttributeName: WBColorHex(0x333333)}];
+                NSRange boldRange = [content rangeOfString:@"输入密码 (默认为1234) "];
+                if (boldRange.location == NSNotFound) {
+                    boldRange = [content rangeOfString:@"输入密码 (默认为1234)"];
+                }
+                if (boldRange.location != NSNotFound) {
+                    [attr addAttribute:NSFontAttributeName value:WBPrimaryBoldFont(16) range:boldRange];
+                }
+                WBPopupDisposableViewController *popup = [[WBPopupDisposableViewController alloc] initWithTitle:@"全局伪装" attributedMessage:attr cancel:@"取消" confirm:@"开启" confirmAction:^(BOOL confirmed, BOOL neverShowAgain) {
+                    if (confirmed) {
+                        WBSettingManager.sharedManager.NeverShowPretenseTipAlert = neverShowAgain;
+                        if (vapp.featureStatusInfo.isLockSwitchOn) {
+                            WBPasswordViewController *passwordVc = [WBPasswordViewController new];
+                            passwordVc.firstSet = FALSE;
+                            passwordVc.vapp = vapp;
+                            passwordVc.type = WBPasswordViewControllerTypeEntry;
+                            passwordVc.successBlock = successBlock;
+                            passwordVc.failBlock = failBlock;
+                            [presenter.navigationController pushViewController:passwordVc animated:YES];
+                        } else {
+                            successBlock();
+                        }
+                    } else {
+                        failBlock();
+                    }
+                }];
+                popup.modalPresentationStyle = UIModalPresentationOverFullScreen;
+                popup.modalTransitionStyle = UIModalTransitionStyleCrossDissolve;
+                [presenter presentViewController:popup animated:NO completion:nil];
+            } else {
+                if (vapp.featureStatusInfo.isLockSwitchOn) {
+                    WBPasswordViewController *passwordVc = [WBPasswordViewController new];
+                    passwordVc.firstSet = FALSE;
+                    passwordVc.vapp = vapp;
+                    passwordVc.type = WBPasswordViewControllerTypeEntry;
+                    passwordVc.successBlock = successBlock;
+                    passwordVc.failBlock = failBlock;
+                    [presenter.navigationController pushViewController:passwordVc animated:YES];
+                } else {
+                    successBlock();
+                }
+            }
+        };
+
+        alertBlock();
+    } else {
+        if (vapp.featureStatusInfo.isLockSwitchOn) {
+            WBPasswordViewController *passwordVc = [WBPasswordViewController new];
+            passwordVc.firstSet = FALSE;
+            passwordVc.vapp = vapp;
+            passwordVc.type = WBPasswordViewControllerTypeEntry;
+            passwordVc.successBlock = ^{
+                vapp.featureStatusInfo.isPretenseSwitchOn = NO;
+                [SVProgressHUD showSuccessWithStatus:@"已关闭全局伪装"];
+                if (setSwitch) setSwitch(NO, YES);
+            };
+            passwordVc.failBlock = ^{ if (setSwitch) setSwitch(YES, YES); };
+            [presenter.navigationController pushViewController:passwordVc animated:YES];
+        } else {
+            vapp.featureStatusInfo.isPretenseSwitchOn = NO;
+            [SVProgressHUD showSuccessWithStatus:@"已关闭全局伪装"];
+            if (setSwitch) setSwitch(NO, YES);
+        }
+    }
+}
