- (void)initWorks {
    [self loadMyApps];
    [self loadDualApps];
    [self loadDeleteUnCleanApps];
}


- (void)loadMyApps {
    NSArray *arrayDict =[NSArray arrayWithContentsOfFile: WBStorageManager.sharedManager.installedVAppListFilePath];
    if (arrayDict == nil) {
        self.myApps = [NSMutableArray array];
    } else {
        self.myApps = [[NSArray modelArrayWithClass:WBVAppModel.class json:arrayDict] mutableCopy];
        for(WBVAppModel *vapp in self.myApps) {
            if (vapp.userInfo == nil) {
                vapp.userInfo = [[WBVAppUserInfo alloc] init];
            }
            vapp.isDownload = YES;
            self.allApps[vapp.bundleId] = vapp;
            [self checkVAppStatusForInstallation:vapp];
        }
    }
}

- (void)loadDualApps {
    [WBVAppManager.sharedManager loadDualAppsWithCallback:^(NSArray<WBVAppModel *> *apps, BOOL success) {
    }];
}

- (void)loadDeleteUnCleanApps {
    NSArray *arrayDict =[NSArray arrayWithContentsOfFile: WBStorageManager.sharedManager.deleteUncleanedVAppListFilePath];
    if (arrayDict == nil) {
        self.deleteUncleanedAppPackages = [NSMutableArray array];
    } else {
        self.deleteUncleanedAppPackages = [[NSArray modelArrayWithClass:WBPackageInfo.class json:arrayDict] mutableCopy];
    }
}



- (void)checkVAppStatusForInstallation:(WBVAppModel *)vapp {
    switch(vapp.status) {
        case WBVappStatusNone:
        case WBVappStatusUnknown:

        case WBVappStatusWaitingDownload:
        case WBVappStatusDownloading:
        case WBVappStatusDownloadError:
        case WBVappStatusDownloadInterrupted:
            [self downloadVApp:vapp];
            break;

        case WBVappStatusWaitingInstall:
        case WBVappStatusInstalling:
        case WBVappStatusInstallError:
            [self installVApp:vapp];

