- (void)dialogueBaseCell:(WBDialogueBaseCell *)cell didSelectedOperation:(WBRichMessageLinkModel *)operation {
    if (!operation) return;

    switch(operation.type) {
        case WBRichMessageLinkTypeFAQ:
            if (1) {
                NSInteger faqId = [operation.link integerValue];
                [self showDetailFAQWithFAQId:faqId];
            }
            break;
        case WBRichMessageLinkTypeArticle:
        case WBRichMessageLinkTypeWebview:
            [self.navigationController pushViewController:[[WBWebViewController alloc] initWithURL:[NSURL URLWithString:operation.link]] animated:YES];
            break;
        case WBRichMessageLinkTypeAppstoreRate:
            [WBAppManager.sharedManager writeReviewInAppStore:@"support"];
            break;
        default:
            if (operation.generalAction) {
                operation.generalAction();
            } else {
                NSLog(@"no action defined for %@", operation.label);
            }
            break;
    }
}

- (void)dialogueBaseCell:(WBDialogueBaseCell *)cell didTriggerRoute:(NSURL *)routePath {
    NSURLComponents *components = [NSURLComponents componentsWithURL:routePath resolvingAgainstBaseURL:NO]; // 解析原始URL
    NSMutableArray<NSURLQueryItem *> *queryItems = [components.queryItems mutableCopy] ?: [NSMutableArray new]; // 获取现有查询参数

    // 添加msgId参数，重构URL，并执行新路由
    NSURLQueryItem *msgIdItem = [NSURLQueryItem queryItemWithName:@"msgId" value:[NSString stringWithFormat:@"%ld", (long)cell.msgId]];
    [queryItems addObject:msgIdItem];
    components.queryItems = queryItems;
    NSURL *modifiedURL = components.URL;
    [WBRouteManager.sharedManager performRoute:modifiedURL sourceInterface:@"support/recents"];
}


#pragma mark - Routing util

- (void)onRoutedWithKeyword:(NSString * _Nullable)keyword {
    if (keyword.length) { // Send keyword with new feedbacks pulled.
        void (^actionBlock)(void) = ^{
            UITextField *textField = self.typeBox.textField;
            textField.text = keyword;
            [self textFieldShouldReturn:textField];
        };
        if (self.isViewLoaded) {
            return actionBlock();
        }
        self.postFeedbackLoadAction = actionBlock;
    } else { // Only pull new feedbacks.
        if (!self.isViewLoaded) return; // Will request all recent feedbacks when viewDidLoad, no need to pull.
        [self pullNewFeedback];
    }
}

@end

