- (void)executeWithDefaultHandler:(nullable WBActionRequestDefaultHandler)defaultHandler {
    NSURL *url = [NSURL URLWithString:self.link];
    NSParameterAssert(url != nil);
    if (self.type == WBLinkActionTypeWBRoute) {
        WBRouteManager *routeManager = [WBRouteManager sharedManager];
        if (defaultHandler) {
