- (void)addOperation:(WBRichMessageLinkType)type style:(WBRichMessageLinkStyle)style label:(NSString *)label link:(NSString * _Nullable)link block:(WBActionBlock _Nullable)block {
    if (_operations == nil) {
        _operations = [NSMutableArray array];
    }
    WBRichMessageLinkModel *operation = [[WBRichMessageLinkModel alloc] init];
    operation.type = type;
    operation.style = style;
    operation.label = label;
    operation.link = link;
    operation.postAction = block;
    [self.operations addObject:operation];
}

